def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(start_pos, end_pos):
        distance = np.linalg.norm(end_pos - start_pos)
        return distance / truck_speed

    def calculate_time_window_penalty(arrival_time, window):
        start, end = window
        if arrival_time < start:
            return (start - arrival_time, 'early')
        elif arrival_time > end:
            return (arrival_time - end, 'late')
        else:
            return (0, 'ontime')

    best_penalty = float('inf')
    best_node = None
    best_index = -1

    for index, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + travel_time
        penalty, status = calculate_time_window_penalty(arrival_time, time_windows[index])

        if status == 'early':
            wait_time = time_windows[index][0] - arrival_time
            if wait_time + current_time < time_windows[index][1]:
                effective_penalty = 0  # Prioritize waiting over skipping if early
            else:
                effective_penalty = float('inf')  # Can't wait too long, skip
        else:
            effective_penalty = penalty  # Late or on-time

        if effective_penalty < best_penalty:
            best_penalty = effective_penalty
            best_node = customer_pos
            best_index = index

    return best_index if best_node is not None else None

