import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.sqrt(np.sum((point1 - point2) ** 2))

    def time_to_reach(truck_pos, customer_pos):
        return calculate_distance(truck_pos, customer_pos) / truck_speed

    n_customers = len(unvisited_customers)
    min_penalty = float('inf')
    best_node = None

    for i in range(n_customers):
        distance = calculate_distance(cur_truck_pos, unvisited_customers[i])
        travel_time = distance / truck_speed
        arrival_time = current_time + travel_time
        window_start, window_end = time_windows[i]

        if arrival_time < window_start:
            wait_time = window_start - arrival_time
            penalty = wait_time
        elif arrival_time > window_end:
            penalty = (arrival_time - window_end)**2
        else:
            penalty = 0  # Arrive within time window

        # Consider clustering of trucks to avoid customer overcrowding
        other_distances = np.array([calculate_distance(other_pos, unvisited_customers[i]) for other_pos in all_truck_pos if not np.array_equal(other_pos, cur_truck_pos)])
        if other_distances.size > 0:
            closest_other_truck_dist = np.min(other_distances)
            penalty += closest_other_truck_dist / 20  # penalty reduced by nearness of other trucks

        if penalty < min_penalty:
            min_penalty = penalty
            best_node = i

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def time_to_reach(current_position, target_position, speed):
        return calculate_distance(current_position, target_position) / speed

    def score_customer(index, customer_pos, time_window):
        arrival_time = current_time + time_to_reach(cur_truck_pos, customer_pos, truck_speed)
        start_window, end_window = time_window
        if arrival_time < start_window:
            return (start_window - arrival_time) ** 2  # penalize too early
        elif arrival_time > end_window:
            return (arrival_time - end_window) ** 2 * 10  # heavily penalize too late
        else:
            return -10 * (end_window - arrival_time)  # bonus for being within the window

    num_customers = len(unvisited_customers)
    scores = np.zeros(num_customers)

    for i in range(num_customers):
        scores[i] = score_customer(i, unvisited_customers[i], time_windows[i])

    best_node = np.argmin(scores)
    return best_node
